css:
.loader {color: var(--loader-color, #0f766e);
  --loader-secondary-color: #5eead4;
  --loader-bg: #ffffff;
  width: 120px;
  height: 20px;
  background:radial-gradient(circle 10px,currentColor 95%,#0000 ) right /calc(200% + 20px) 100%,linear-gradient(currentColor 0 0) center/100% 6px;
  background-repeat: no-repeat;
  -webkit-mask: radial-gradient(circle 4px,#0000 93%,currentColor ) right/calc(200% + 20px) 100%;
  animation: l6 1s infinite linear;
}@keyframes l6 {100% {background-position: left;
  -webkit-mask-position:left}}
